select SiteCode, FormName, FormID, PreadmissionId, ClientId, QuestionID 
     , QuestionOrderID = Row_Number() over(Partition by q.FormName, q.FormId, q.ClientId, q.QuestionId order by q.QuestionId) 
     , QuestionText, OptionID, AnswerValue, Createdby, CreatedOn, UpdatedBy, UpdatedOn, IsDeleted from (
   Select SiteCode = '" + st.SiteCode.ToString() + "', 'Consent to Treatment with an Approved Narcotic'  as [FormName] 
        , '4-' + convert(varchar, c.ClientId) + '-' + convert(varchar, c.PreAdmissionId) + '-' + convert(varchar, c.id) as [FormID] 
        , c.PreAdmissionId, c.ClientId, 0 as QuestionID, 1 as QuestionOrderID, null as QuestionText, null as [OptionID], null as AnswerValue 
        , c.Createdby, convert(date, c.CreatedOn) as [CreatedOn], c.ModifiedBy as [UpdatedBy], convert(date, ModifiedOn) as [UpdatedOn]
        , IsDeleted = case when isnull(c.IsDeleted,0) = 0 and pa.IsDeleted <> 1 and isnull(pa.DataFormId,0) >= 0 and isnull(df.IsDeleted,0) = 0 then 0 else 1 end
     from [dbo].NCPIE c
     inner join SF_PatientPreAdmission pa on (c.PreAdmissionId = pa.ID)
     left join SF_DataForms df on (c.DataFormId = df.Id)
   ) q

select * from StateFactForm where DataFormId < 0
select abs(DataFormId), DataFormId from SF_PatientPreAdmission where DataFormId < 0
    select * from SF_DataForms where FormName = 'Consent to Treatment with an Approved Narcotic' --id in (7595, 7596)
*/

