 from (select SiteCode = 'B27', ft.FormName, f.id as FormId, f.ClientId, f.CreatedOn, f.UpdatedOn, IsDeleted = case when isnull(f.IsDeleted,0) = 0 and pa.IsDeleted <> 1 and isnull(pa.DataFormId,0) >= 0 and isnull(d.IsDeleted,0) = 0 then 0 else 1 end  from dbo.Form f left join FormTemplate ft on (f.FormTemplateId = ft.Id) inner join [dbo].[SF_PatientPreAdmission] pa on (f.PreAdmissionId = pa.ID)  left join dbo.SF_DataForms d on (pa.DataFormId = d.Id)/*')*/ union select SiteCode = 'B27', ft.FormName, f.id as FormId, f.ClientId, f.CreatedOn, f.UpdatedOn, IsDeleted = case when isnull(f.IsDeleted,0) = 0 and pa.IsDeleted <> 1 and isnull(pa.DataFormId,0) >= 0 and isnull(d.IsDeleted,0) = 0 then 0 else 1 end from dbo.Form f left join FormTemplate ft on(f.FormTemplateId = ft.Id) inner join [dbo].[SF_PatientPreAdmission] pa on (f.PreAdmissionId = pa.ID)  left join dbo.SF_DataForms d on (pa.DataFormId = d.Id) where /*(f.CreatedOn >= '1/1/2024' or isnull(f.UpdatedOn, f.CreatedOn) >= '1/1/2024') or*/ f.Isdeleted = 1) x 
